import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { getOpenLibraryCoverUrl } from '../services/bookCovers';
import './BookCard.css';

// ── Category themes: each has a gradient pair + pattern type ─────────────────
const CATEGORY_THEMES = {
  Fiction:       { from: '#1a0a2e', to: '#2d1b4e', accent: '#a78bfa', pattern: 'waves'    },
  'Non-Fiction': { from: '#0a1628', to: '#1a2d4e', accent: '#60a5fa', pattern: 'grid'     },
  Science:       { from: '#0a1f1f', to: '#0f3333', accent: '#34d399', pattern: 'hexagon'  },
  History:       { from: '#1f0f00', to: '#3a1f00', accent: '#d97706', pattern: 'lines'    },
  Technology:    { from: '#0f0f2e', to: '#1a1a4e', accent: '#818cf8', pattern: 'circuit'  },
  Romance:       { from: '#2e0a1a', to: '#4e1a2d', accent: '#f472b6', pattern: 'curves'   },
  Mystery:       { from: '#0a0f1a', to: '#1a2033', accent: '#7aa2c4', pattern: 'dots'     },
  Programming:   { from: '#0f1a0a', to: '#1a2d10', accent: '#86efac', pattern: 'code'     },
  Biography:     { from: '#1a1000', to: '#2d1f00', accent: '#fbbf24', pattern: 'portrait' },
  'Self-Help':   { from: '#1a0f00', to: '#2d1f0a', accent: '#fb923c', pattern: 'rays'     },
};

const DEFAULT_THEME = { from: '#141414', to: '#252525', accent: '#c4a24a', pattern: 'lines' };

// ── SVG patterns inside the cover ────────────────────────────────────────────
function CoverPattern({ pattern, accent, width = 200, height = 280 }) {
  const op = 0.18; // base opacity

  switch (pattern) {
    case 'waves':
      return (
        <g opacity={op}>
          {[0,1,2,3,4,5].map(i => (
            <path
              key={i}
              d={`M0 ${60 + i * 38} Q50 ${40 + i * 38} 100 ${60 + i * 38} T200 ${60 + i * 38}`}
              stroke={accent} strokeWidth="1.2" fill="none"
            />
          ))}
        </g>
      );

    case 'grid':
      return (
        <g opacity={op}>
          {[20,40,60,80,100,120,140,160,180].map(x => (
            <line key={`v${x}`} x1={x} y1="0" x2={x} y2={height} stroke={accent} strokeWidth="0.7" />
          ))}
          {[30,60,90,120,150,180,210,240,270].map(y => (
            <line key={`h${y}`} x1="0" y1={y} x2={width} y2={y} stroke={accent} strokeWidth="0.7" />
          ))}
        </g>
      );

    case 'hexagon':
      return (
        <g opacity={op}>
          {[[60,70],[140,70],[100,140],[60,210],[140,210]].map(([cx,cy], i) => (
            <polygon
              key={i}
              points={`${cx},${cy-28} ${cx+24},${cy-14} ${cx+24},${cy+14} ${cx},${cy+28} ${cx-24},${cy+14} ${cx-24},${cy-14}`}
              stroke={accent} strokeWidth="1" fill="none"
            />
          ))}
        </g>
      );

    case 'dots':
      return (
        <g opacity={op + 0.05}>
          {Array.from({ length: 6 }).map((_, row) =>
            Array.from({ length: 5 }).map((_, col) => (
              <circle
                key={`${row}-${col}`}
                cx={20 + col * 40} cy={30 + row * 46}
                r="2.5" fill={accent}
              />
            ))
          )}
        </g>
      );

    case 'circuit':
      return (
        <g opacity={op}>
          <path d="M20 60 H80 V100 H160 V140 H120 V180 H80 V220" stroke={accent} strokeWidth="1" fill="none"/>
          <path d="M140 40 V80 H100 V120 H60 V160" stroke={accent} strokeWidth="1" fill="none"/>
          {[[80,100],[160,140],[80,180],[60,160],[100,120]].map(([cx,cy],i) => (
            <circle key={i} cx={cx} cy={cy} r="4" stroke={accent} strokeWidth="1" fill="none"/>
          ))}
        </g>
      );

    case 'rays':
      return (
        <g opacity={op}>
          {Array.from({ length: 12 }).map((_, i) => {
            const angle = (i * 30) * Math.PI / 180;
            const x2 = 100 + Math.cos(angle) * 180;
            const y2 = 140 + Math.sin(angle) * 180;
            return <line key={i} x1="100" y1="140" x2={x2} y2={y2} stroke={accent} strokeWidth="0.8" />;
          })}
        </g>
      );

    case 'curves':
      return (
        <g opacity={op}>
          <path d="M-20 140 C40 80, 100 200, 160 100 S240 60, 300 140" stroke={accent} strokeWidth="1.5" fill="none"/>
          <path d="M-20 180 C40 120, 100 240, 160 140 S240 100, 300 180" stroke={accent} strokeWidth="1.5" fill="none"/>
          <path d="M-20 100 C40 40, 100 160, 160 60 S240 20, 300 100" stroke={accent} strokeWidth="1.5" fill="none"/>
        </g>
      );

    case 'code':
      return (
        <g opacity={op + 0.08} fontFamily="monospace" fontSize="11" fill={accent}>
          <text x="14" y="55">{'const book = {'}</text>
          <text x="14" y="80">{'  title: "...",'}</text>
          <text x="14" y="105">{'  read: true'}</text>
          <text x="14" y="130">{'}'}</text>
          <text x="14" y="175">{'// keep reading'}</text>
          <text x="14" y="215">{'fn next_page() {'}</text>
          <text x="14" y="240">{'  learn()'}</text>
          <text x="14" y="265">{'}'}</text>
        </g>
      );

    case 'portrait':
      return (
        <g opacity={op}>
          <circle cx="100" cy="90" r="38" stroke={accent} strokeWidth="1.2" fill="none"/>
          <path d="M44 220 C44 170 156 170 156 220" stroke={accent} strokeWidth="1.2" fill="none"/>
          <rect x="60" y="230" width="80" height="4" fill={accent} rx="2"/>
          <rect x="70" y="244" width="60" height="4" fill={accent} rx="2" opacity="0.5"/>
        </g>
      );

    case 'lines':
    default:
      return (
        <g opacity={op}>
          {[50, 90, 130, 170, 210].map((y, i) => (
            <line key={i} x1="20" y1={y} x2={180 - i * 10} y2={y}
              stroke={accent} strokeWidth={i === 0 ? 2 : 1} />
          ))}
        </g>
      );
  }
}

// ── Shimmer text helper — truncates long titles ───────────────────────────────
function truncate(str, max) {
  if (!str) return '';
  return str.length > max ? str.slice(0, max - 1) + '…' : str;
}

// ── Main Book Cover ──────────────────────────────────────────────────────────
function BookCover({ book, theme }) {
  const [imageError, setImageError] = React.useState(false);

  // Try to get ISBN from book data or localStorage
  let bookData = { ...book };

  // Check if ISBN is stored in localStorage (fallback if backend doesn't support it)
  if (!bookData.isbn && typeof window !== 'undefined') {
    const storedIsbn = localStorage.getItem(`book_isbn_${book.id}`);
    if (storedIsbn) {
      bookData.isbn = storedIsbn;
    }
  }

  // Check if coverUrl is stored in localStorage
  if (!bookData.coverUrl && typeof window !== 'undefined') {
    const storedUrl = localStorage.getItem(`book_cover_${book.id}`);
    if (storedUrl) {
      bookData.coverUrl = storedUrl;
    }
  }

  // Get cover URL
  const coverUrl = getOpenLibraryCoverUrl(bookData);

  if (coverUrl && !imageError) {
    return (
      <img 
        src={coverUrl} 
        alt={book.title}
        className="book-cover-image"
        onError={() => setImageError(true)}
      />
    );
  }

  // Fallback to beautiful SVG pattern if image fails
  return (
    <BookCoverSVG
      title={book.title}
      author={book.author}
      category={book.category || 'Book'}
      accent={theme.accent}
      from={theme.from}
      to={theme.to}
      pattern={theme.pattern}
    />
  );
}

// ── Main Book Cover SVG ───────────────────────────────────────────────────────
function BookCoverSVG({ title, author, category, accent, from, to, pattern }) {
  const initial  = (title || 'B')[0].toUpperCase();
  const short    = truncate(title,  22);
  const authorSh = truncate(author, 26);

  // Break title into two lines if long
  const words      = (short || '').split(' ');
  const mid        = Math.ceil(words.length / 2);
  const line1      = words.slice(0, mid).join(' ');
  const line2      = words.slice(mid).join(' ');
  const singleLine = short.length <= 14;

  return (
    <svg viewBox="0 0 200 280" xmlns="http://www.w3.org/2000/svg" width="100%" height="100%">
      <defs>
        <linearGradient id={`bg-${initial}-${category}`} x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor={from} />
          <stop offset="100%" stopColor={to} />
        </linearGradient>
        <linearGradient id={`shine-${initial}`} x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor="rgba(255,255,255,0.06)" />
          <stop offset="50%" stopColor="rgba(255,255,255,0.12)" />
          <stop offset="100%" stopColor="rgba(255,255,255,0.04)" />
        </linearGradient>
      </defs>

      {/* Background */}
      <rect width="200" height="280" fill={`url(#bg-${initial}-${category})`} rx="2"/>

      {/* Subtle top shine */}
      <rect width="200" height="100" fill={`url(#shine-${initial})`} rx="2"/>

      {/* Pattern */}
      <CoverPattern pattern={pattern} accent={accent} />

      {/* Left binding strip */}
      <rect x="0" y="0" width="8" height="280" fill={accent} opacity="0.75" rx="1"/>

      {/* Large faded initial — decorative */}
      <text
        x="105" y="175"
        textAnchor="middle"
        fontFamily="Georgia, serif"
        fontSize="120"
        fontWeight="700"
        fill={accent}
        opacity="0.08"
        letterSpacing="-4"
      >
        {initial}
      </text>

      {/* Category chip */}
      <rect x="14" y="16" width={category.length * 7.2 + 16} height="20" rx="10"
        fill={accent} opacity="0.18"/>
      <text x="22" y="30" fontFamily="system-ui,sans-serif" fontSize="9.5"
        fontWeight="700" fill={accent} letterSpacing="0.08em" textTransform="uppercase"
        style={{ textTransform: 'uppercase' }}>
        {(category || 'BOOK').toUpperCase()}
      </text>

      {/* Title */}
      <rect x="0" y="192" width="200" height="88" fill="rgba(0,0,0,0.55)"/>
      {singleLine ? (
        <text x="14" y="218" fontFamily="Georgia,serif" fontSize="16"
          fontWeight="700" fill="#f8f6f2" letterSpacing="-0.3">
          {short}
        </text>
      ) : (
        <>
          <text x="14" y="215" fontFamily="Georgia,serif" fontSize="15"
            fontWeight="700" fill="#f8f6f2" letterSpacing="-0.3">
            {line1}
          </text>
          <text x="14" y="234" fontFamily="Georgia,serif" fontSize="15"
            fontWeight="700" fill="#f8f6f2" letterSpacing="-0.3">
            {line2}
          </text>
        </>
      )}

      {/* Divider */}
      <line x1="14" y1="242" x2="100" y2="242" stroke={accent} strokeWidth="1.5" opacity="0.7"/>

      {/* Author */}
      <text x="14" y="258" fontFamily="system-ui,sans-serif" fontSize="10.5"
        fill="#8a8278" fontStyle="italic">
        {authorSh}
      </text>
    </svg>
  );
}

// ── BookCard ──────────────────────────────────────────────────────────────────
export default function BookCard({ book, onEdit, onDelete, onAddToCart, isAdmin, isLoggedIn }) {
  const [adding, setAdding] = useState(false);
  const [added,  setAdded]  = useState(false);

  const theme   = CATEGORY_THEMES[book.category] || DEFAULT_THEME;
  const inStock = book.stock > 0;

  const handleAddToCart = async () => {
    if (!onAddToCart || adding || added) return;
    setAdding(true);
    try {
      await onAddToCart(book);
      setAdded(true);
      setTimeout(() => setAdded(false), 2000);
    } catch {
      // error handled in parent
    } finally {
      setAdding(false);
    }
  };

  return (
    <div className="book-card fade-up">
      {/* Cover */}
      <div className="book-cover">
        <BookCover book={book} theme={theme} />
        {!inStock && (
          <div className="book-out-of-stock">Out of Stock</div>
        )}
      </div>

      {/* Info */}
      <div className="book-info">
        <h3 className="book-title">{book.title}</h3>
        <p className="book-author">by {book.author}</p>

        <div className="book-meta">
          <span className="book-price">&#8377;{book.price?.toFixed(2)}</span>
          <span className="book-stock" style={{ color: inStock ? 'var(--green)' : 'var(--red)' }}>
            {inStock ? `${book.stock} in stock` : 'Out of stock'}
          </span>
        </div>

        {/* Actions */}
        <div className="book-actions">
          <Link to={`/books/${book.id}`} className="btn btn-outline btn-xs">
            View
          </Link>

          {isLoggedIn && !isAdmin && inStock && (
            <button
              className={`btn btn-xs btn-cart ${added ? 'btn-cart-added' : ''}`}
              onClick={handleAddToCart}
              disabled={adding || added}
            >
              {adding ? (
                '...'
              ) : added ? (
                <>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
                    <polyline points="20 6 9 17 4 12"/>
                  </svg>
                  Added
                </>
              ) : (
                <>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                    <path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.98-1.72L23 6H6"/>
                  </svg>
                  Add to Cart
                </>
              )}
            </button>
          )}

          {isAdmin && (
            <>
              <button className="btn btn-ghost btn-xs" onClick={() => onEdit(book)}>
                Edit
              </button>
              <button className="btn btn-danger btn-xs" onClick={() => onDelete(book.id)}>
                Delete
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
